// 6b. the two Quarries — ALL surface stone lives here (tier-2 obsidian aside):
// stone is a place you travel to, not a pebble you trip over. Each is a
// carved stone-floor pit with a dirt rim, ringed inside with rock nodes.
const QUARRIES = [
  { name: 'North Quarry', cx: 124, cy: 30 },
  { name: 'South Quarry', cx: 48, cy: 126 },
];
for (const q of QUARRIES) {
  fillCircle(q.cx, q.cy, 7, 'dirt', ['grass', 'swamp']);
  fillCircle(q.cx, q.cy, 5.5, 'stone_floor', ['grass', 'dirt', 'swamp']);
}
carvePath([
  [100, 100],
  [112, 62],
  [124, 36],
]); // → north quarry
carvePath([
  [75, 120],
  [60, 123],
  [52, 126],
]); // → south quarry (branches off the delta path, fords the river)

// 7. beaches: grass adjacent to water becomes sand
const sandify: [number, number][] = [];
for (let y = 0; y < H; y++) {
  for (let x = 0; x < W; x++) {
    if (ground[y][x] !== 'grass') continue;
    for (const [dx, dy] of [
      [1, 0],
      [-1, 0],
      [0, 1],
      [0, -1],
    ]) {
      if (inBounds(x + dx, y + dy) && ground[y + dy][x + dx] === 'water') {
        sandify.push([x, y]);
        break;
      }
    }
  }
}
for (const [x, y] of sandify) ground[y][x] = 'sand';

// 8. v2: the Guardian's arena — a cliff-walled court in the north-east ruins.
// Terrain is written BEFORE node generation so no node lands inside, and the
// arena consumes no RNG — v1 node ids stay byte-stable for existing saves.
const ARENA = { x: 169, y: 15, w: ARENA_W, h: ARENA_H };
const GUARDIAN_HOME = { tx: ARENA.x + Math.floor(ARENA_W / 2) - 1, ty: ARENA.y + 1 }; // 3x3, top-center
const SEAL_GATE = [ARENA.x + 7, ARENA.x + 8, ARENA.x + 9].map((tx) => ({ tx, ty: ARENA.y + ARENA.h })); // south entrance
for (let y = ARENA.y - 1; y <= ARENA.y + ARENA.h; y++) {
  for (let x = ARENA.x - 1; x <= ARENA.x + ARENA.w; x++) {
    const isWall = x === ARENA.x - 1 || x === ARENA.x + ARENA.w || y === ARENA.y - 1 || y === ARENA.y + ARENA.h;
    ground[y][x] = isWall ? 'cliff' : 'stone_floor';
  }
}
for (const g of SEAL_GATE) ground[g.ty][g.tx] = 'stone_floor'; // the entrance gap the Seal blocks
carvePath([
  [162, 38],
  [170, 34],
  [SEAL_GATE[1].tx, SEAL_GATE[1].ty + 2],
]); // → arena entrance

// 8b. spawn clearing — keep it open
const SPAWN = { tx: 100, ty: 100 };

// ---------------------------------------------------------------- zones
// ADR-0012: each Zone carries a `dangerous` flag. The core (near spawn) + the
// un-zoned Deep Jungle stay a SAFE haven — peaceful Wildlife roams there, but no
// predator ever spawns/attacks (the safe start the Journey assumes). Predators
// live ONLY in the danger-flagged FRONTIER Zones: "combat is something you walk
// into." Adding the field does not touch zoneAt (name-keyed) or the RNG order, so
// every Node id + Zone rect stays byte-stable.
const zones = [
  // quarry zones come first — zoneAt takes the first hit, and both overlap
  // broader zones (the South Quarry sits inside the River Delta rectangle)
  { name: 'North Quarry', x: 116, y: 22, w: 16, h: 16, dangerous: false },
  { name: 'South Quarry', x: 40, y: 118, w: 16, h: 16, dangerous: false },
  { name: 'Spawn Clearing', x: 88, y: 88, w: 24, h: 24, dangerous: false },
  { name: 'Thundering Falls', x: 86, y: 6, w: 30, h: 34, dangerous: false },
  { name: 'Ancient Ruins', x: 140, y: 14, w: 48, h: 44, dangerous: false },
  { name: 'Dense Grove', x: 128, y: 66, w: 62, h: 62, dangerous: false },
  { name: 'Sunken Swamp', x: 126, y: 134, w: 64, h: 56, dangerous: false },
  { name: 'River Delta', x: 12, y: 120, w: 70, h: 74, dangerous: false },
  { name: 'Hidden Grove', x: 6, y: 56, w: 30, h: 40, dangerous: false },
  // ---- FRONTIER zones (ADR-0009), appended after the core. Every rect lies
  // wholly in the east (x>=200) OR south (y>=200) frontier, so no CORE cell
  // (x<200 AND y<200) ever matches one — core zoneAt results are unchanged.
  // These are the danger-flagged WILDS (ADR-0012): predators prowl here.
  { name: 'Highland Crags', x: 224, y: 10, w: 62, h: 72, dangerous: true }, // east-north: the hill + 3rd quarry + vista
  { name: 'Overgrown Temple', x: 214, y: 116, w: 72, h: 76, dangerous: true }, // east-south: tier-2 grove + lore
  { name: 'Mangrove Coast', x: 100, y: 226, w: 108, h: 70, dangerous: true }, // south: fishing + shipwreck treasure
  { name: 'The Cavern Mouth', x: 16, y: 222, w: 80, h: 74, dangerous: true }, // south-west: the Delve entrance
  // ---- REALM district Zones (ADR-0017), appended last. Every rect lies wholly
  // beyond the pinned 300×300 map (x>=300 or y>=300), so no pre-existing tile
  // can ever match one — zoneAt for the old World is unchanged, first-hit order
  // preserved. Deliberately NOT dangerous: predators never spawn in a Realm.
  { name: 'The Sunken Mire', x: 100, y: 300, w: 108, h: 72, dangerous: false }, // rung 1 Realm (T2 stub; T5 fills it in)
  { name: 'The Hushdark', x: 16, y: 300, w: 80, h: 72, dangerous: false }, // rung 2 Realm (ADR-0017; T6)
  { name: 'The Green Terraces', x: 220, y: 300, w: 120, h: 72, dangerous: false }, // rung 3 Realm (ADR-0017; T7)
];

function zoneAt(x: number, y: number): string {
  for (const z of zones) {
    if (x >= z.x && x < z.x + z.w && y >= z.y && y < z.y + z.h) return z.name;
  }
  return 'Deep Jungle';
}

