function nearWater(x: number, y: number): boolean {
  for (let dy = -1; dy <= 1; dy++) {
    for (let dx = -1; dx <= 1; dx++) {
      if (inBounds(x + dx, y + dy) && ground[y + dy][x + dx] === 'water') return true;
    }
  }
  return false;
}

let nodeId = 0;
function tryPlaceNode(type: NodeOut['type'], x: number, y: number): void {
  if (!inBounds(x, y)) return;
  const key = `${x},${y}`;
  if (occupied.has(key)) return;
  const g = ground[y][x];
  // mire_peat/mire_mud only exist in district space, so accepting them cannot
  // change any pinned-map placement outcome; echo_crystal_seam is placed ONLY in
  // the Hushdark district (never during pinned gen), so accepting it on stone_floor
  // cannot change any pinned placement either
  if (
    g !== 'grass' && g !== 'swamp' && g !== 'mire_peat' && g !== 'mire_mud' &&
    !((type === 'rock' || type === 'obsidian_rock') && g === 'stone_floor') &&
    !(type === 'echo_crystal_seam' && g === 'stone_floor')
  )
    return;
  if (Math.abs(x - SPAWN.tx) <= 2 && Math.abs(y - SPAWN.ty) <= 2) return;
  if ((type === 'tree' || type === 'hardwood_tree') && nearWater(x, y)) return;
  occupied.add(key);
  nodes.push({ id: `n${nodeId++}`, type, tx: x, ty: y });
}

// jittered 2x2 grid keeps nodes from clumping into unreadable blobs.
// BOUNDED TO THE CORE: the exact same iteration + RNG sequence as the original
// 200×200 map, so every core node id is byte-stable (frontier nodes append later).
for (let gy = 1; gy < CORE_H - 1; gy += 2) {
  for (let gx = 1; gx < CORE_W - 1; gx += 2) {
    const x = gx + Math.floor(rand(0, 2));
    const y = gy + Math.floor(rand(0, 2));
    if (!inBounds(x, y)) continue;
    const zone = zoneAt(x, y);
    const roll = rng();
    const tree = treeDensity[zone] ?? 0.1;
    const bush = bushDensity[zone] ?? 0.01;
    const vine = vineDensity[zone] ?? 0.005;
    if (roll < tree) tryPlaceNode('tree', x, y);
    else if (roll < tree + bush) tryPlaceNode('fruit_bush', x, y);
    else if (roll < tree + bush + vine) tryPlaceNode('fiber_vine', x, y);
  }
}

// the Quarries' rock clusters — a ring plus an inner scatter, with walkable
