// ============================================================ FRONTIER (ADR-0009)
// Everything below is APPENDED after the pinned core: every core node id is
// already assigned above, so nothing here can shift them. All authoring stays in
// the frontier (x>=CORE_W OR y>=CORE_H); a helper guards paths against the core.

const inFrontier = (x: number, y: number) => x >= CORE_W || y >= CORE_H;

/** like carvePath, but never writes a CORE tile — keeps existing builds pinned */
function carveFrontierPath(points: [number, number][]) {
  for (let i = 0; i < points.length - 1; i++) {
    const [x0, y0] = points[i];
    const [x1, y1] = points[i + 1];
    const steps = Math.ceil(Math.hypot(x1 - x0, y1 - y0) * 2);
    for (let s = 0; s <= steps; s++) {
      const t = s / steps;
      const x = Math.round(x0 + (x1 - x0) * t + Math.sin(t * 7 + i * 2) * 1.2);
      const y = Math.round(y0 + (y1 - y0) * t);
      for (let dy = 0; dy <= 1; dy++) {
        for (let dx = 0; dx <= 1; dx++) {
          const px = x + dx;
          const py = y + dy;
          if (!inBounds(px, py) || !inFrontier(px, py)) continue;
          const g = ground[py][px];
          if (g === 'grass' || g === 'swamp' || g === 'stone_floor') ground[py][px] = 'dirt';
          else if (g === 'water') ground[py][px] = 'sand';
        }
      }
    }
  }
}

/** the faux-elevation primitive (ADR-0009): what GameScene needs to render a hill */
interface ElevationRegion {
  name: string;
  /** which terrace this is — 1 = first plateau, 2 = a plateau stacked on top, … */
  level: number;
  bounds: { x: number; y: number; w: number; h: number };
  /** walkable plateau-top tiles — entities on these get the elevation depth bump */
  plateau: [number, number][];
  /** cliff-edge tiles (blocked) drawn as a downward face */
  faces: [number, number][];
  /** the sole walkable ascent */
  ramp: [number, number][];
  /** reaching here lifts minimap fog around the crag */
  vista: { tx: number; ty: number };
  /** fog-lift radius in chunks */
  vistaChunkRadius: number;
}
const elevationRegions: ElevationRegion[] = [];

/** carve one terrace rect: cliff-ring border (blocked) + walkable top + one south ramp */
function carveTerrace(name: string, level: number, rect: { x: number; y: number; w: number; h: number }, vistaR: number) {
  const rampX = rect.x + Math.floor(rect.w / 2);
  const plateau: [number, number][] = [];
  const faces: [number, number][] = [];
  const ramp: [number, number][] = [];
  for (let y = rect.y; y < rect.y + rect.h; y++) {
    for (let x = rect.x; x < rect.x + rect.w; x++) {
      if (!inBounds(x, y)) continue;
      const edge = x === rect.x || x === rect.x + rect.w - 1 || y === rect.y || y === rect.y + rect.h - 1;
      const isRamp = y === rect.y + rect.h - 1 && x === rampX; // the sole ascent, mid-south edge
      if (isRamp) {
        ground[y][x] = 'dirt';
        ramp.push([x, y]);
      } else if (edge) {
        ground[y][x] = 'cliff'; // blocked=2 — the raised edge that can't be walked off
        faces.push([x, y]);
      } else {
        ground[y][x] = 'stone_floor'; // the walkable top (GameScene grasses it over)
        plateau.push([x, y]);
      }
    }
  }
  elevationRegions.push({
    name, level, bounds: rect, plateau, faces, ramp,
    vista: { tx: rect.x + Math.floor(rect.w / 2), ty: rect.y + Math.floor(rect.h / 2) },
    vistaChunkRadius: vistaR,
  });
  return rampX;
}

// ---- Highland Crags: a TWO-TIER faux-elevation hill — you climb a ramp to the
// terrace, then a second ramp to the smaller summit (so it reads as CLIMBABLE, not
// one flat court). The lower terrace is carved first; the upper plateau is stacked
// inside it, its cliff-ring dropping onto the terrace. GameScene renders both tiers
// with per-level depth bumps + faces; the summit vista lifts the most fog.
const cragRampX = (() => {
  const lower = { x: 240, y: 24, w: 22, h: 18 };
  const upper = { x: 246, y: 25, w: 10, h: 8 }; // stacked on the terrace, toward the north
  const rampX = carveTerrace('Highland Crags', 1, lower, 6);
  // a short dirt approach from the south so the lower ramp is reachable from the ground
  for (let dy = 0; dy < 3; dy++) {
    const yy = lower.y + lower.h + dy;
    if (inBounds(rampX, yy) && ground[yy][rampX] === 'grass') ground[yy][rampX] = 'dirt';
  }
  // the upper terrace overwrites the middle of the lower plateau; drop it from the
  // lower region's plateau list so those tiles read as the SUMMIT, not the terrace
  carveTerrace('Highland Crags Summit', 2, upper, 12);
  const lowerRegion = elevationRegions[elevationRegions.length - 2];
  const upperTiles = new Set<string>();
  for (let y = upper.y; y < upper.y + upper.h; y++) for (let x = upper.x; x < upper.x + upper.w; x++) upperTiles.add(`${x},${y}`);
  lowerRegion.plateau = lowerRegion.plateau.filter(([x, y]) => !upperTiles.has(`${x},${y}`));
  return rampX;
})();

// ---- Highland Crags 3rd quarry: a stone-floor pit at the hill's foot, ringed
// with rock nodes (like the core Quarries; appended ids so core stays byte-stable)
const cragQuarry = { cx: cragRampX, cy: 54 };
fillCircle(cragQuarry.cx, cragQuarry.cy, 6, 'dirt', ['grass']);
